176→    if (chapResult.error) {
177→        console.error('supabase error fetching chapters:', chapResult.error.message);
178→    }
179→
180→    // Filter chapters for non-authors
181→    const isAuthor = story.author_id === userId;
182→    const chapters = chapResult.data || [];
183→    const visibleChapters = isAuthor
184→        ? chapters
185→        : chapters.filter(c => c.status === 'published');
186→
187→    // Fetch user flags
188→    let hasVoted = false;
189→    let inLibrary = false;
190→    let readingProgress = null;
191→
192→    if (userId) {
193→        const [voteRes, libRes, progressRes] = await Promise.all([
194→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
195→            supabase.from('story_library').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
