197→        ]);
198→
199→        hasVoted = !!voteRes.data;
200→        inLibrary = !!libRes.data;
201→        readingProgress = progressRes.data || null;
202→    }
203→
204→    return {
205→        ...story,
206→        users: authorMap[story.author_id] || null,
207→        chapters: visibleChapters,
208→        has_voted: hasVoted,
209→        in_library: inLibrary,
210→        reading_progress: readingProgress,
211→        is_author: isAuthor,
212→    };
