 42→const extractBearerToken = (authHeader = "") => {
 43→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 44→    if (!trimmed) return "";
 45→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 46→    if (bearerMatch?.[1]) return bearerMatch[1].trim();
 47→    return trimmed;
 48→};
