### Step 4: Backfill Existing Stories (Optional Script)

If there are already stories in the database, they will have `NULL` embeddings. Create a one-time backfill script.

**File to create:** `server/scripts/backfillStoryEmbeddings.js`

Pattern to follow: The project already has `server/scripts/backfillUsernames.js` as a reference for backfill scripts.

```js
import supabase from "../services/supabase.js";
import GenerateEmbeddings from "../utils/GenerateEmbeddings.js";

const BATCH_SIZE = 50;

const backfillStoryEmbeddings = async () => {
    let processed = 0;
    let offset = 0;

    while (true) {
        const { data: stories, error } = await supabase
            .from('stories')
            .select('id, title, description')
            .is('embedding', null)
            .order('created_at', { ascending: true })
            .range(offset, offset + BATCH_SIZE - 1);

        if (error) {
            console.error('failed to fetch stories batch:', error.message);
            break;
        }

        if (!stories || stories.length === 0) {
            console.log('no more stories to backfill');
            break;
        }

        for (const story of stories) {
            try {
                const embedding = await GenerateEmbeddings(story.title || '', story.description || '');
                if (Array.isArray(embedding) && embedding.length > 0) {
                    const { error: updateError } = await supabase
                        .from('stories')
                        .update({ embedding })
                        .eq('id', story.id);

                    if (updateError) {
                        console.warn(`failed to update story ${story.id}:`, updateError.message);
                    } else {
                        processed++;
                        console.log(`[${processed}] embedded story ${story.id}: "${story.title}"`);
                    }
                } else {
                    console.warn(`empty embedding for story ${story.id}, skipping`);
                }
            } catch (err) {
                console.warn(`error processing story ${story.id}:`, err?.message || err);
            }
        }

        offset += BATCH_SIZE;
    }

    console.log(`backfill complete. processed ${processed} stories.`);
    process.exit(0);
};

backfillStoryEmbeddings();
```

